#include <gtest/gtest.h>

#include "solvers/chain.h"

TEST(TestChain, ALCType2) {
    // 5 5- r2c2 -9- r8c2 =9= r8c9 =1= r8c3 -1- r2c3 -8- r2c5 =8= r8c5 -8- r8c8 -5 => r2c8,r8c2<>5
    Inst inst = {
        0xF1,//type
        8,// length
         17,  4,  (17),  (8),   0x71,  (8),   0x78,  (8),
    0x78, 0,  0x72, 0, (18), 0,  (16), 0,
   (16), (4)
    };
    std::vector<uint16_t> executees = {0x1004};
    Grid grid("");
    findAIC(grid);
    EXPECT_EQ(*grid.getInst(), inst);
    EXPECT_EQ(grid.getExec()->mode, false);
    EXPECT_EQ(grid.getExec()->executees, executees);
}

TEST(TestChain, HARD) {
    // 5 5- r2c2 -9- r8c2 =9= r8c9 =1= r8c3 -1- r2c3 -8- r2c5 =8= r8c5 -8- r8c8 -5 => r2c8,r8c2<>5
    Inst inst = {
    };
    std::vector<uint16_t> executees = {};
    Grid grid("");
    findAIC(grid);
    EXPECT_EQ(*grid.getInst(), inst);
    EXPECT_EQ(grid.getExec()->mode, false);
    EXPECT_EQ(grid.getExec()->executees, executees);
}
